      "content": "from fastapi import FastAPI, Request, Form, HTTPException
from fastapi.templating import Jinja2Templates
from fastapi.staticfiles import StaticFiles
from fastapi.responses import HTMLResponse, RedirectResponse
import uuid
from datetime import datetime

app = FastAPI()
templates = Jinja2Templates(directory='templates')

# Mock Database representing the defined tables
db = {
    "customers": [],
    "tickets": [],
    "support_agents": [
        {"id": "1", "name": "Alex Rivera", "email": "alex@support.com", "role": "Senior Lead"},
        {"id": "2", "name": "Sam Smith", "email": "sam@support.com", "role": "Agent"}
    ],
    "chat_messages": {}
}

@app.get('/', response_class=HTMLResponse)
async def home(request: Request):
    return templates.TemplateResponse(request=request, name='home.html', context={})

@app.get('/tickets', response_class=HTMLResponse)
async def tickets_page(request: Request):
    return templates.TemplateResponse(request=request, name='tickets.html', context={'tickets': db['tickets']})

@app.get('/tickets/create', response_class=HTMLResponse)
async def create_ticket_page(request: Request):
    return templates.TemplateResponse(request=request, name='create_ticket.html', context={})

@app.post('/api/tickets')
async def create_ticket(subject: str = Form(...), priority: str = Form(...)):
    ticket_id = str(uuid.uuid4())[:8]
    new_ticket = {
        'id': ticket_id,
        'customer_id': 'user_123',
        'subject': subject,
        'priority': priority,
        'status': 'Open',
        'created_at': datetime.now().strftime('%Y-%m-%d %H:%M'),
        'assigned_agent_id': None
    }
    db['tickets'].append(new_ticket)
    db['chat_messages'][ticket_id] = []
    return RedirectResponse(url='/tickets', status_code=303)

@app.get('/chat/{ticket_id}', response_class=HTMLResponse)
async def chat_view(request: Request, ticket_id: str):
    ticket = next((t for t in db['tickets'] if t['id'] == ticket_id), None)
    if not ticket: raise HTTPException(status_code=404)
    messages = db['chat_messages'].get(ticket_id, [])
    return templates.TemplateResponse(request=request, name='chat.html', context={'ticket': ticket, 'messages': messages})

@app.post('/api/chat')
async def post_message(ticket_id: str = Form(...), message: str = Form(...)):
    if ticket_id in db['chat_messages']:
        db['chat_messages'][ticket_id].append({
            'sender_type': 'customer',
            'message_content': message,
            'sent_at': datetime.now().strftime('%H:%M')
        })
    return RedirectResponse(url=f'/chat/{ticket_id}', status_code=303)

@app.get('/admin-dashboard', response_class=HTMLResponse)
async def admin_view(request: Request):
    stats = {
        'total': len(db['tickets']),
        'open': len([t for t in db['tickets'] if t['status'] == 'Open']),
        'avg_response': '14m'
    }
    return templates.TemplateResponse(request=request, name='admin.html', context={'tickets': db['tickets'], 'agents': db['support_agents'], 'stats': stats})"
    }
  ]
}

